-- Populacao municipal IBGE/SIDRA para calculo de incidencia, prevalencia e taxa de deteccao.
-- Fonte oficial: SIDRA tabela 6579, variavel 9324 (Populacao residente estimada).

CREATE TABLE IF NOT EXISTS ibge_municipio_populacao (
  id BIGSERIAL PRIMARY KEY,
  codigo_ibge TEXT NOT NULL,
  municipio TEXT NOT NULL,
  uf TEXT NOT NULL DEFAULT 'SP',
  ano INT NOT NULL,
  populacao BIGINT NOT NULL CHECK (populacao >= 0),
  fonte TEXT NOT NULL,
  fonte_url TEXT NOT NULL,
  atualizado_em TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (codigo_ibge, ano)
);

CREATE INDEX IF NOT EXISTS idx_ibge_pop_codigo_ano ON ibge_municipio_populacao (codigo_ibge, ano);
CREATE INDEX IF NOT EXISTS idx_ibge_pop_municipio_ano ON ibge_municipio_populacao (municipio, ano);
CREATE INDEX IF NOT EXISTS idx_ibge_pop_uf_ano ON ibge_municipio_populacao (uf, ano);

ALTER TABLE ibge_municipio_populacao DISABLE ROW LEVEL SECURITY;

ON CONFLICT (codigo_ibge, ano) DO UPDATE SET
  municipio = EXCLUDED.municipio,
  uf = EXCLUDED.uf,
  populacao = EXCLUDED.populacao,
  fonte = EXCLUDED.fonte,
  fonte_url = EXCLUDED.fonte_url,
  atualizado_em = NOW();
